Thanks for taking the time to report this.

Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)
[queue_test.tar.gz](https://github.com/verilator/verilator/files/5119017/queue_test.tar.gz)

## Test
```systemverilog
module tb_top(
    input clk
);

    logic q [$];
    int cycle = 0;

    always@(posedge clk) begin
        q.push_front(1'b1);
        cycle <= cycle + 1'b1;
    end

    always@(posedge clk) begin
        if(cycle == 'd1) begin
            if (q.pop_back() == 1'b1) $display("Passed");
            else begin
                $display("Failed");
                $fatal;
            end
        end
    end

endmodule
```

```cpp
#include "verilated.h"
#include "Vtb_top.h"
#include <ctime>

double sc_time_stamp() {return 2 * 1e9;}

int main(int argc, char **argv, char **env)
{
    Vtb_top* top = new Vtb_top;
    for (uint8_t d1=0, d2=0; true; d1++, d2++) {
        top->clk = !top->clk;
        top->eval();
        if (Verilated::gotFinish()) break;
    }
    top->final();
    exit(0);
}
```

